using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>(entity =>
        {
            entity.ToContainer("Products");

            // BREAKING CHANGE 1 — Discriminator property renamed from "Discriminator" to "$type" in EF Core 9.
            // Existing 500K documents store "Discriminator", and direct SQL queries reference c.Discriminator.
            // Restore the old property name so reads/writes stay compatible.
            entity.HasDiscriminator<string>("Discriminator")
                  .HasValue<Product>("Product");

            // BREAKING CHANGE 2 — id values no longer include the discriminator prefix in EF Core 9.
            // EF8 wrote ids as "Product|123"; EF9 defaults to just "123".
            // Without this flag, every existing document becomes unreachable by key lookup.
            entity.HasDiscriminatorInJsonId();

            // BREAKING CHANGE 3 — HasIndex is not meaningful for the Cosmos provider.
            // EF8 silently ignored it; EF9 throws InvalidOperationException.
            // Cosmos DB manages indexing via its own indexing policy — removed.
        });
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

