    // BREAKING CHANGE 4 — Synchronous I/O removed in the Cosmos provider for EF Core 9.
    // ToList(), First(), SaveChanges(), etc. now throw InvalidOperationException.
    // All data access must use async counterparts (ToListAsync, SaveChangesAsync, …).
    async Task FindProducts(ProductContext ctx)
